const resp = $input.first().json;
const aiText = resp.candidates?.[0]?.content?.parts?.[0]?.text || '';
let jsonText = aiText.trim().replace(/^```json\s*/, '').replace(/^```\s*/, '').replace(/\s*```$/, '');
let parsed;
try { parsed = JSON.parse(jsonText); } catch (e) { parsed = { 粉專主體: aiText.trim(), 社團主體: aiText.trim() }; }
const src = $('白名單清洗').first().json;
// 鎖價後處理：文案內非官方總價的價格字串，替換回官方值
const price = src['總價萬'];
let body = String(parsed['粉專主體'] || '').trim();
if (price) {
  const aiNum = (body.match(/(\d{3,7})\s*萬/) || [])[1];
  if (aiNum && Number(aiNum) !== Number(price)) body = body.split(aiNum + ' 萬').join(price + ' 萬').split(aiNum + '萬').join(price + '萬');
}
const 粉專footer = '\n\n📞 薛先生 0912877583（同 LINE）\nLINE：https://line.me/ti/p/kg1pMk4vX8\n\n—\n凱璿誼峰不動產有限公司\n經紀業特許字號：高市地政籍字第11034791100號\n證照字號：（111）登字第417208號';
const 社團footer = '\n\n—\n凱璿誼峰不動產有限公司｜薛先生 0912877583\n經紀業特許字號：高市地政籍字第11034791100號';
const 粉專文案 = body + 粉專footer;
const 社團文案 = String(parsed['社團主體'] || '').trim() + 社團footer;
return [{ json: { ...src, 粉專文案, 社團文案 } }];

// 把 Notion 那邊的 pageId / 舊貼文 id 併回文案流
const ctx = $('挑一件重發').first().json;
return [{ json: { ...$input.first().json, ...ctx } }];

const fbids = $input.all().map(i => i.json?.id).filter(Boolean).slice(0, 10);
const ctx = $('補上下文').first().json;
return [{ json: { ...ctx, fbids } }];

const resp = $input.first().json;
const id = resp.id || resp.post_id || '';
const ctx = $('收集 media id').first().json;
const parts = String(id).split('_');
const permalink = id ? (parts.length === 2 ? `https://www.facebook.com/${parts[0]}/posts/${parts[1]}` : `https://www.facebook.com/${id}`) : '';
return [{ json: { ...ctx, fbPostId: id, permalink } }];

